import React, { useEffect, useState, useCallback } from "react";
import axios from "axios";
import { Card, Row, Col, Button, Form } from "react-bootstrap";
import { Pie } from "react-chartjs-2";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from "chart.js";
import { useNavigate } from "react-router-dom";

ChartJS.register(ArcElement, Tooltip, Legend);

const ReconciliationDashboard = () => {
  const [stats, setStats] = useState({ total: 0, matched: 0, partial: 0, duplicate: 0, unmatched: 0, accuracy: 0 });
  const [filters, setFilters] = useState({ startDate: "", endDate: "", status: "", uploadedBy: "" });
  const navigate = useNavigate();

  const buildQuery = () => {
    const qp = [];
    if (filters.startDate) qp.push(`startDate=${filters.startDate}`);
    if (filters.endDate) qp.push(`endDate=${filters.endDate}`);
    if (filters.status) qp.push(`status=${encodeURIComponent(filters.status)}`);
    if (filters.uploadedBy) qp.push(`uploadedBy=${encodeURIComponent(filters.uploadedBy)}`);
    return qp.length ? `?${qp.join("&")}` : "";
  };

  const fetchSummary = useCallback(async () => {
    try {
      const token = localStorage.getItem("token");
      const url = `http://localhost:4000/api/reconcile/summary${buildQuery()}`;
      const res = await axios.get(url, { headers: { Authorization: `Bearer ${token}` } });
      const data = res.data || [];
      calculateStats(data);
    } catch (err) {
      console.error("Error fetching filtered summary:", err);
    }
  }, [filters]);

  useEffect(() => {
    fetchSummary();
  }, [fetchSummary]);

  const calculateStats = (data) => {
    const matched = data.filter((r) => r.status === "Matched").length;
    const partial = data.filter((r) => r.status === "Partially Matched").length;
    const duplicate = data.filter((r) => r.status === "Duplicate").length;
    const unmatched = data.filter((r) => r.status === "Unmatched").length;
    const total = data.length;
    const accuracy = total ? ((matched + partial * 0.5) / total) * 100 : 0;
    setStats({ total, matched, partial, duplicate, unmatched, accuracy: accuracy.toFixed(2) });
  };

  const chartData = {
    labels: ["Matched", "Partial", "Duplicate", "Unmatched"],
    datasets: [{ label: "Reconciliation Summary", data: [stats.matched, stats.partial, stats.duplicate, stats.unmatched], backgroundColor: ["#4CAF50", "#FFEB3B", "#9C27B0", "#F44336"] }]
  };

  return (
    <div className="container mt-4">
      <div className="d-flex justify-content-between">
        <h3>Reconciliation Dashboard</h3>
        <div>
          <Button variant="secondary" onClick={() => navigate("/history")}>Job History</Button>
        </div>
      </div>

      {/* Filters */}
      <Form className="row g-2 align-items-end mt-3">
        <div className="col-auto">
          <label>Start</label>
          <Form.Control type="date" value={filters.startDate} onChange={(e) => setFilters((p) => ({ ...p, startDate: e.target.value }))} />
        </div>
        <div className="col-auto">
          <label>End</label>
          <Form.Control type="date" value={filters.endDate} onChange={(e) => setFilters((p) => ({ ...p, endDate: e.target.value }))} />
        </div>
        <div className="col-auto">
          <label>Status</label>
          <Form.Select value={filters.status} onChange={(e) => setFilters((p) => ({ ...p, status: e.target.value }))}>
            <option value="">All</option>
            <option>Matched</option>
            <option>Partially Matched</option>
            <option>Duplicate</option>
            <option>Unmatched</option>
          </Form.Select>
        </div>
        <div className="col-auto">
          <label>Uploaded By</label>
          <Form.Control placeholder="user id or name" value={filters.uploadedBy} onChange={(e) => setFilters((p) => ({ ...p, uploadedBy: e.target.value }))} />
        </div>
        <div className="col-auto">
          <Button variant="primary" onClick={fetchSummary}>Apply</Button>
        </div>
        <div className="col-auto">
          <Button variant="light" onClick={() => { setFilters({ startDate: "", endDate: "", status: "", uploadedBy: "" }); }}>Clear</Button>
        </div>
      </Form>

      {/* Summary cards */}
      <Row className="mt-4">
        <Col md={2}><Card className="p-3 text-center bg-primary text-white"><h5>Total</h5><h3>{stats.total}</h3></Card></Col>
        <Col md={2}><Card className="p-3 text-center bg-success text-white"><h5>Matched</h5><h3>{stats.matched}</h3></Card></Col>
        <Col md={2}><Card className="p-3 text-center bg-warning text-dark"><h5>Partial</h5><h3>{stats.partial}</h3></Card></Col>
        <Col md={2}><Card className="p-3 text-center bg-info text-white"><h5>Duplicate</h5><h3>{stats.duplicate}</h3></Card></Col>
        <Col md={2}><Card className="p-3 text-center bg-danger text-white"><h5>Unmatched</h5><h3>{stats.unmatched}</h3></Card></Col>
        <Col md={2}><Card className="p-3 text-center bg-secondary text-white"><h5>Accuracy (%)</h5><h3>{stats.accuracy}</h3></Card></Col>
      </Row>

      <div className="mt-4 w-50 mx-auto">
        <Pie data={chartData} />
      </div>

      <div className="text-center mt-4">
        <Button variant="dark" href="/reconciliation-view">🔍 View Detailed Records</Button>
      </div>
    </div>
  );
};

export default ReconciliationDashboard;
